function makeMultiplier($factor) {
    return function($n) {
        return $n * $factor;
    };
}
$double = makeMultiplier(2);
echo $double(5);

function makeMultiplier($factor) {
    return function($n) use ($factor) {
        return $n * $factor;
    };
}
$double = makeMultiplier(2);
echo $double(5);

function makeMultiplier($factor) {
    return fn($n) => $n * $factor;
}
$triple = makeMultiplier(3);
echo $triple(5);

